404→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
405→  RETURN SELECT
406→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
407→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
408→  FROM $entity;
409→};
