 1→import { z } from "zod";
 2→
 3→const extractionEntityBaseSchema = z.object({
 4→  tempId: z.string().min(1),
 5→  kind: z.enum(["project", "feature", "task", "decision", "question"]),
 6→  text: z.string().min(3).max(200),
 7→  confidence: z.number().min(0).max(1),
 8→  evidence: z.string().min(1),
 9→}).strict();
10→
11→const extractionEntityWithAssigneeSchema = extractionEntityBaseSchema.extend({
12→  assignee_name: z.string().min(1),
13→}).strict();
14→
15→const extractionEntityWithResolvedFromSchema = extractionEntityBaseSchema.extend({
16→  resolvedFromMessageId: z.string().min(1),
17→}).strict();
18→
19→const extractionEntityWithAssigneeAndResolvedFromSchema = extractionEntityBaseSchema.extend({
20→  assignee_name: z.string().min(1),
21→  resolvedFromMessageId: z.string().min(1),
22→}).strict();
23→
24→const extractionEntitySchema = z.union([
25→  extractionEntityBaseSchema,
26→  extractionEntityWithAssigneeSchema,
27→  extractionEntityWithResolvedFromSchema,
28→  extractionEntityWithAssigneeAndResolvedFromSchema,
29→]);
30→
31→export const extractionRelationshipSchema = z.object({
32→  kind: z.string().min(1),
33→  fromTempId: z.string().min(1),
34→  toTempId: z.string().min(1),
35→  confidence: z.number().min(0).max(1),
36→  fromText: z.string().min(1),
37→  toText: z.string().min(1),
38→}).strict();
39→
40→export const extractionResultSchema = z.object({
41→  entities: z.array(extractionEntitySchema),
42→  relationships: z.array(extractionRelationshipSchema),
43→  tools: z.array(z.string().min(1)),
44→}).strict();
45→
46→export type ExtractionPromptEntity = z.infer<typeof extractionEntitySchema>;
47→export type ExtractionPromptRelationship = z.infer<typeof extractionRelationshipSchema>;
48→export type ExtractionPromptOutput = z.infer<typeof extractionResultSchema>;
49→
50→export function parseExtractionOutput(payload: unknown):
51→  | { ok: true; data: ExtractionPromptOutput }
52→  | { ok: false; error: string } {
53→  const result = extractionResultSchema.safeParse(payload);
54→  if (result.success) {
55→    return { ok: true, data: result.data };
56→  }
57→
58→  return {
59→    ok: false,
60→    error: result.error.issues[0]?.message ?? "Invalid extraction payload",
61→  };
62→}
