  1→import { useEffect, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import type { EntityDetailResponse, EntityKind } from "../../../shared/contracts";
  4→import { EntityBadge } from "./EntityBadge";
  5→import { RelationshipList } from "./RelationshipList";
  6→import { ProvenanceSection } from "./ProvenanceSection";
  7→import { useViewState } from "../../stores/view-state";
  8→import { confirmDecision, overrideDecision, markTaskComplete } from "../../graph/actions";
  9→
 10→const CONFIRMABLE_STATUSES = new Set(["extracted", "proposed", "provisional", "inferred"]);
 11→
 12→export function EntityDetailPanel({
 13→  entityId,
 14→  workspaceId,
 15→  onClose,
 16→  onEntityClick,
 17→}: {
 18→  entityId: string;
 19→  workspaceId: string;
 20→  onClose: () => void;
 21→  onEntityClick: (entityId: string) => void;
 22→}) {
 23→  const [detail, setDetail] = useState<EntityDetailResponse | undefined>();
 24→  const [loading, setLoading] = useState(true);
 25→  const [error, setError] = useState<string | undefined>();
 26→  const [actionPending, setActionPending] = useState(false);
 27→  const navigateToChat = useViewState((s) => s.navigateToChat);
 28→  const navigate = useNavigate();
 29→
 30→  useEffect(() => {
 31→    setLoading(true);
 32→    setError(undefined);
 33→
 34→    fetch(`/api/entities/${encodeURIComponent(entityId)}?workspaceId=${encodeURIComponent(workspaceId)}`)
 35→      .then(async (response) => {
 36→        if (!response.ok) {
 37→          const body = await response.text();
 38→          throw new Error(body);
 39→        }
 40→        return response.json() as Promise<EntityDetailResponse>;
 41→      })
 42→      .then((data) => {
 43→        setDetail(data);
 44→        setLoading(false);
 45→      })
 46→      .catch((err) => {
 47→        setError(err instanceof Error ? err.message : "Failed to load entity");
 48→        setLoading(false);
 49→      });
 50→  }, [entityId, workspaceId]);
 51→
 52→  function handleJumpToMessage(messageId: string) {
 53→    navigateToChat(messageId);
 54→    void navigate({ to: "/" });
 55→  }
 56→
 57→  async function handleConfirm() {
 58→    if (!detail || actionPending) return;
 59→    setActionPending(true);
 60→    try {
 61→      await confirmDecision(workspaceId, entityId);
 62→      setDetail((prev) =>
 63→        prev
 64→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "confirmed" } } }
 65→          : prev,
 66→      );
 67→    } finally {
 68→      setActionPending(false);
 69→    }
 70→  }
 71→
 72→  async function handleOverride() {
 73→    if (!detail || actionPending) return;
 74→    const newSummary = window.prompt("New decision summary:");
 75→    if (!newSummary) return;
 76→    setActionPending(true);
 77→    try {
 78→      await overrideDecision(workspaceId, entityId, newSummary);
 79→      setDetail((prev) =>
 80→        prev
 81→          ? {
 82→              ...prev,
 83→              entity: {
 84→                ...prev.entity,
 85→                name: newSummary,
 86→                data: { ...prev.entity.data, status: "overridden", summary: newSummary },
 87→              },
 88→            }
 89→          : prev,
 90→      );
 91→    } finally {
 92→      setActionPending(false);
 93→    }
 94→  }
 95→
 96→  async function handleComplete() {
 97→    if (!detail || actionPending) return;
 98→    setActionPending(true);
 99→    try {
100→      await markTaskComplete(workspaceId, entityId);
101→      setDetail((prev) =>
102→        prev
103→          ? { ...prev, entity: { ...prev.entity, data: { ...prev.entity.data, status: "done" } } }
104→          : prev,
105→      );
106→    } finally {
107→      setActionPending(false);
108→    }
109→  }
110→
111→  if (loading) {
112→    return (
113→      <aside className="entity-detail-panel">
114→        <p className="entity-detail-meta">Loading...</p>
115→      </aside>
116→    );
117→  }
118→
119→  if (error || !detail) {
120→    return (
121→      <aside className="entity-detail-panel">
122→        <div className="entity-detail-header">
123→          <p className="entity-detail-meta">{error ?? "Entity not found"}</p>
124→          <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
125→        </div>
126→      </aside>
127→    );
128→  }
129→
130→  const kind = detail.entity.kind as EntityKind;
131→  const status = (detail.entity.data.status as string | undefined) ?? "";
132→  const rationale = detail.entity.data.rationale as string | undefined;
133→
134→  const showConfirm = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
135→  const showOverride = kind === "decision" && CONFIRMABLE_STATUSES.has(status);
136→  const showComplete = kind === "task" && status !== "done";
137→
138→  return (
139→    <aside className="entity-detail-panel">
140→      <div className="entity-detail-header">
141→        <div>
142→          <EntityBadge kind={kind} />
143→          <h3>{detail.entity.name}</h3>
144→        </div>
145→        <button type="button" className="entity-detail-close" onClick={onClose}>&times;</button>
146→      </div>
147→
148→      <div className="entity-detail-section">
149→        <h4>Metadata</h4>
150→        <dl className="entity-detail-meta">
151→          {status ? (
152→            <>
153→              <dt>Status</dt>
154→              <dd>{status}</dd>
155→            </>
156→          ) : undefined}
157→          {detail.entity.data.confidence !== undefined ? (
158→            <>
159→              <dt>Confidence</dt>
160→              <dd>{(detail.entity.data.confidence as number).toFixed(2)}</dd>
161→            </>
162→          ) : undefined}
163→          {detail.entity.data.created_at ? (
164→            <>
165→              <dt>Created</dt>
166→              <dd>{new Date(detail.entity.data.created_at as string).toLocaleDateString()}</dd>
167→            </>
168→          ) : undefined}
169→          {detail.entity.data.owner_name ? (
170→            <>
171→              <dt>Owner</dt>
172→              <dd>{detail.entity.data.owner_name as string}</dd>
173→            </>
174→          ) : undefined}
175→          {detail.entity.data.priority ? (
176→            <>
177→              <dt>Priority</dt>
178→              <dd>{detail.entity.data.priority as string}</dd>
179→            </>
180→          ) : undefined}
181→        </dl>
182→      </div>
183→
184→      {rationale ? (
185→        <div className="entity-detail-section">
186→          <h4>Rationale</h4>
187→          <p className="entity-detail-meta">{rationale}</p>
188→        </div>
189→      ) : undefined}
190→
191→      <RelationshipList relationships={detail.relationships} onEntityClick={onEntityClick} />
192→
193→      <ProvenanceSection provenance={detail.provenance} onJumpToMessage={handleJumpToMessage} />
194→
195→      {(showConfirm || showOverride || showComplete) ? (
196→        <div className="entity-detail-actions">
197→          {showConfirm ? (
198→            <button type="button" disabled={actionPending} onClick={handleConfirm}>
199→              Confirm
200→            </button>
201→          ) : undefined}
202→          {showOverride ? (
203→            <button type="button" disabled={actionPending} onClick={handleOverride}>
204→              Override
205→            </button>
206→          ) : undefined}
207→          {showComplete ? (
208→            <button type="button" disabled={actionPending} onClick={handleComplete}>
209→              Mark Complete
210→            </button>
211→          ) : undefined}
212→        </div>
213→      ) : undefined}
214→    </aside>
215→  );
216→}
