  1→import { generateObject } from "ai";
  2→import {
  3→  extractionResultSchema,
  4→  type ExtractionPromptOutput,
  5→} from "./schema";
  6→import { buildExtractionSystemPrompt } from "./prompt";
  7→import type { ExtractionGraphContextRow, MessageContextRow } from "./types";
  8→import { elapsedMs, logError, logInfo } from "../http/observability";
  9→
 10→export async function extractStructuredGraph(input: {
 11→  extractionModel: any;
 12→  conversationHistory: MessageContextRow[];
 13→  currentMessage?: MessageContextRow;
 14→  graphContext: ExtractionGraphContextRow[];
 15→  sourceText: string;
 16→  onboarding: boolean;
 17→  heading?: string;
 18→  workspaceName?: string;
 19→  projectNames?: string[];
 20→}): Promise<ExtractionPromptOutput> {
 21→  const startedAt = performance.now();
 22→  logInfo("extraction.generate.started", "Structured extraction started", {
 23→    onboarding: input.onboarding,
 24→    hasHeading: input.heading !== undefined,
 25→    contextMessageCount: input.conversationHistory.length,
 26→    hasCurrentMessage: input.currentMessage !== undefined,
 27→    graphContextCount: input.graphContext.length,
 28→    sourceLength: input.sourceText.length,
 29→  });
 30→
 31→  try {
 32→    const extractionOutput = await generateObject({
 33→      model: input.extractionModel,
 34→      schema: extractionResultSchema,
 35→      system: buildExtractionSystemPrompt({ onboarding: input.onboarding }),
 36→      prompt: [
 37→        "Conversation history (reference resolution only):",
 38→        formatExtractionConversationHistory(input.conversationHistory),
 39→        "",
 40→        "Current message (extract only from this text when message metadata exists):",
 41→        formatExtractionCurrentMessage(input.currentMessage, input.sourceText),
 42→        "",
 43→        "Resolved-from lineage constraints:",
 44→        formatResolvedFromConstraints(input.currentMessage, input.conversationHistory),
 45→        "",
 46→        "Existing graph context (semantic index of prior extracted entities):",
 47→        formatExtractionGraphContext(input.graphContext),
 48→        "",
 49→        "Workspace scope:",
 50→        formatWorkspaceScope(input.workspaceName, input.projectNames),
 51→        input.heading ? `Section heading: ${input.heading}` : "",
 52→        "",
 53→        "Current source text:",
 54→        input.sourceText,
 55→      ]
 56→        .filter((line) => line.length > 0)
 57→        .join("\n"),
 58→    });
 59→
 60→    const output = extractionOutput.object as ExtractionPromptOutput;
 61→    logInfo("extraction.generate.completed", "Structured extraction completed", {
 62→      onboarding: input.onboarding,
 63→      entityCount: output.entities.length,
 64→      relationshipCount: output.relationships.length,
 65→      toolCount: output.tools.length,
 66→      durationMs: elapsedMs(startedAt),
 67→    });
 68→
 69→    return output;
 70→  } catch (error) {
 71→    logError("extraction.generate.failed", "Structured extraction failed", error, {
 72→      onboarding: input.onboarding,
 73→      durationMs: elapsedMs(startedAt),
 74→    });
 75→    throw error;
 76→  }
 77→}
 78→
 79→function formatExtractionConversationHistory(rows: MessageContextRow[]): string {
 80→  if (rows.length === 0) {
 81→    return "(no prior messages)";
 82→  }
 83→
 84→  return rows.map((row) => `[message:${row.id.id as string}] ${row.role.toUpperCase()}: ${row.text}`).join("\n");
 85→}
 86→
 87→function formatExtractionCurrentMessage(currentMessage: MessageContextRow | undefined, sourceText: string): string {
 88→  if (!currentMessage) {
 89→    return `(no message metadata; source text: ${sourceText})`;
 90→  }
 91→
 92→  return `[message:${currentMessage.id.id as string}] ${currentMessage.role.toUpperCase()}: ${currentMessage.text}`;
 93→}
 94→
 95→function formatExtractionGraphContext(rows: ExtractionGraphContextRow[]): string {
 96→  if (rows.length === 0) {
 97→    return "(no prior extracted entities)";
 98→  }
 99→
100→  return rows
101→    .map((row) => {
102→      const table = row.id.tb;
103→      return `[entity:${table}:${row.id.id as string}] ${row.kind}: ${row.text} (confidence ${row.confidence.toFixed(2)}, source message ${row.sourceMessage.id as string})`;
104→    })
105→    .join("\n");
106→}
107→
108→function formatWorkspaceScope(workspaceName?: string, projectNames?: string[]): string {
109→  if (!workspaceName) {
110→    return "(no workspace context)";
111→  }
112→
113→  const lines = [`Workspace: "${workspaceName}"`];
114→  if (projectNames && projectNames.length > 0) {
115→    lines.push(`Existing projects: ${projectNames.map((name) => `"${name}"`).join(", ")}`);
116→  } else {
117→    lines.push("Existing projects: none");
118→  }
119→
120→  return lines.join("\n");
121→}
122→
123→function formatResolvedFromConstraints(
124→  currentMessage: MessageContextRow | undefined,
125→  conversationHistory: MessageContextRow[],
126→): string {
127→  if (!currentMessage) {
128→    return "Current message id unavailable; omit resolvedFromMessageId.";
129→  }
130→
131→  const currentMessageId = currentMessage.id.id as string;
132→  if (conversationHistory.length === 0) {
133→    return [
134→      `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
135→      "Allowed resolvedFromMessageId values (history only): none",
136→      "Omit resolvedFromMessageId.",
137→    ].join("\n");
138→  }
139→
140→  const historyMessageIds = conversationHistory.map((row) => row.id.id as string);
141→  return [
142→    `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
143→    `Allowed resolvedFromMessageId values (history only): ${historyMessageIds.join(", ")}`,
144→    "Use one of the allowed ids exactly, or omit resolvedFromMessageId.",
145→  ].join("\n");
146→}
