187→export async function maybeUpgradeMergedEntityName(
188→  surreal: Surreal,
189→  kind: PersistableExtractableEntityKind,
190→  incomingText: string,
191→  candidate: CandidateEntityRow,
192→  now: Date,
193→): Promise<string> {
194→  if (!isRicherEntityName(incomingText, candidate.text)) {
195→    return candidate.text;
196→  }
197→
198→  if (kind === "project" || kind === "feature") {
199→    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
200→      name: incomingText,
201→      updated_at: now,
202→    });
203→    return incomingText;
204→  }
205→
206→  if (kind === "task") {
207→    await surreal.update(candidate.id as RecordId<"task", string>).merge({
208→      title: incomingText,
209→      updated_at: now,
210→    });
211→    return incomingText;
212→  }
213→
214→  if (kind === "decision") {
215→    await surreal.update(candidate.id as RecordId<"decision", string>).merge({
216→      summary: incomingText,
217→      updated_at: now,
218→    });
219→    return incomingText;
220→  }
221→
222→  await surreal.update(candidate.id as RecordId<"question", string>).merge({
223→    text: incomingText,
224→    updated_at: now,
225→  });
226→
227→  return incomingText;
228→}
