439→export async function appendWorkspaceTools(
440→  surreal: Surreal,
441→  workspaceRecord: RecordId<"workspace", string>,
442→  toolsToAdd: string[],
443→  now: Date,
444→): Promise<void> {
445→  const [rows] = await surreal
446→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
447→      workspace: workspaceRecord,
448→    })
449→    .collect<[Array<{ tools?: string[] }>]>();
450→
451→  const existingTools = rows[0]?.tools ?? [];
452→  const merged = [...new Set([...existingTools, ...toolsToAdd])];
453→  await surreal.update(workspaceRecord).merge({
454→    tools: merged,
455→    updated_at: now,
456→  });
457→}
