 4→// Resolved hex values for OKLCH entity colors — Three.js/WebGL cannot parse CSS variables.
 5→export function entityColor(kind: EntityKind): string {
 6→  switch (kind) {
 7→    case "project": return "#3b82f6";   // oklch(0.65 0.15 250)
 8→    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9→    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10→    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
11→    case "question": return "#a855f7";  // oklch(0.65 0.15 300)
12→    case "person": return "#f97316";    // oklch(0.65 0.15 25)
13→    case "workspace": return "#3b82f6";
14→  }
15→}
16→
17→function titleCase(s: string): string {
18→  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
19→}
20→
21→export function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
22→  const connectionCounts = new Map<string, number>();
23→  for (const edge of raw.edges) {
24→    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
25→    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
26→  }
27→
28→  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
29→    const kind = entity.kind as EntityKind;
30→    const kindBoost = kind === "project" ? 20
31→      : kind === "feature" ? 10
32→      : kind === "person" ? 8
33→      : 0;
34→    return {
35→      id: entity.id,
36→      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
37→      fill: entityColor(kind),
38→      data: {
39→        kind,
40→        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
41→        status: undefined,
42→      },
43→    };
44→  });
45→
46→  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
47→    id: edge.id,
48→    source: edge.fromId,
49→    target: edge.toId,
50→    label: titleCase(edge.kind.replace(/_/g, " ")),
51→    data: {
52→      type: edge.kind,
53→      confidence: edge.confidence,
54→    },
55→  }));
56→
57→  return { nodes, edges };
58→}
