185→        conversationRecord,
186→        workspaceRecord: input.workspaceRecord,
187→        currentMessageRecord: input.userMessageRecord,
188→        latestUserText: input.userText,
189→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
190→        messages: assistantContextRows.map((row) => ({
191→          role: row.role,
192→          text: row.text,
193→        })),
194→        onToken: async (token) => {
195→          input.deps.sse.emitEvent(input.messageId, {
196→            type: "token",
197→            messageId: input.messageId,
198→            token,
199→          });
200→        },
201→      });
202→
203→      assistantText = graphAwareResponse.text.trim();
204→    } else {
205→      const assistantReply = await generateOnboardingAssistantReply({
206→        assistantModel: input.deps.assistantModel,
207→        surreal: input.deps.surreal,
208→        onboardingState: onboardingAfter,
209→        contextRows: assistantContextRows,
210→        latestUserText: input.userText,
211→        workspaceRecord: input.workspaceRecord,
212→        latestEntities: persistedEntities.map((entity) => ({
213→          kind: entity.kind,
214→          text: entity.text,
215→          confidence: entity.confidence,
216→        })),
217→        latestTools: dedupedTools,
218→      });
219→
220→      assistantText = assistantReply.message.trim();
221→      assistantSuggestions = assistantReply.suggestions;
222→
223→      for (const token of assistantText.split(" ")) {
224→        input.deps.sse.emitEvent(input.messageId, {
225→          type: "token",
226→          messageId: input.messageId,
227→          token: `${token} `,
228→        });
229→        await new Promise((resolve) => setTimeout(resolve, 25));
230→      }
231→    }
232→
233→    assistantSuggestions = sanitizeAssistantSuggestions(
234→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
235→      3,
236→    );
237→
238→    const summaryBlock = buildExtractionComponentBlock(
239→      persistedEntities,
240→      persistedRelationships,
241→      input.deps.config.extractionDisplayThreshold,
242→    );
243→
244→    if (summaryBlock) {
245→      if (onboardingAfter === "complete") {
246→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
247→        for (const token of streamChunk.split(" ")) {
248→          input.deps.sse.emitEvent(input.messageId, {
249→            type: "token",
250→            messageId: input.messageId,
251→            token: `${token} `,
252→          });
253→        }
254→      }
255→
256→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
257→    }
258→
259→    if (assistantText.trim().length === 0) {
260→      assistantText = "I could not generate a response for that request.";
261→    }
262→
263→    const assistantMessageRecord = new RecordId("message", input.messageId);
264→    await input.deps.surreal.create(assistantMessageRecord).content({
265→      conversation: conversationRecord,
266→      role: "assistant",
267→      text: assistantText,
268→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
269→      createdAt: now,
270→    });
271→
272→    await input.deps.surreal.update(conversationRecord).merge({
273→      updatedAt: now,
274→    });
275→
276→    void persistEmbeddings({
277→      surreal: input.deps.surreal,
278→      embeddingModel: input.deps.embeddingModel,
279→      embeddingDimension: input.deps.config.embeddingDimension,
280→      assistantMessageRecord,
281→      assistantText,
282→      entities: embeddingTargets,
283→    }).catch(() => undefined);
284→
285→    input.deps.sse.emitEvent(input.messageId, {
286→      type: "extraction",
287→      messageId: input.messageId,
288→      entities: persistedEntities,
289→      relationships: persistedRelationships,
290→    });
291→
292→    if (seedItems.length > 0) {
293→      input.deps.sse.emitEvent(input.messageId, {
294→        type: "onboarding_seed",
295→        messageId: input.messageId,
296→        seeds: seedItems,
297→      });
298→    }
